# Break-glass access portal (simplified)
import boto3
from datetime import datetime, timedelta, timezone
from typing import Optional

def request_breakglass_access(
    requester_id: str,
    session_id: Optional[str],  # None = broad access (requires dual approval)
    reason: str,
    approver_id: str,
) -> str:
    """Grant temporary access to full conversation content."""
    if session_id is None:
        # Broad access requires dual approval
        require_second_approver(approver_id)

    # Create time-limited IAM session policy
    sts = boto3.client("sts")
    condition = {}
    if session_id:
        condition = {
            "StringEquals": {"s3:prefix": [f"sessions/{session_id}/"]}
        }

    policy = {
        "Version": "2012-10-17",
        "Statement": [{
            "Effect": "Allow",
            "Action": ["s3:GetObject"],
            "Resource": f"arn:aws:s3:::conversation-logs-restricted/*",
            "Condition": condition
        }]
    }

    # Issue short-lived credentials (4 hours max)
    creds = sts.assume_role(
        RoleArn="arn:aws:iam::ACCOUNT:role/ConversationLogReader",
        RoleSessionName=f"breakglass-{requester_id}-{int(datetime.now().timestamp())}",
        Policy=str(policy),
        DurationSeconds=14400  # 4 hours
    )

    # Write audit event
    write_audit_event({
        "event": "breakglass_access_granted",
        "requester": requester_id,
        "approver": approver_id,
        "session_id": session_id or "BROAD",
        "reason": reason,
        "expires_at": (datetime.now(timezone.utc) + timedelta(hours=4)).isoformat(),
        "timestamp": datetime.now(timezone.utc).isoformat(),
    })

    return creds["Credentials"]["SessionToken"]
